# AUP use case classifier

from dataclasses import dataclass
from typing import Literal

UseCategory = Literal["permitted","restricted","prohibited"]

@dataclass
class AiUseCase:
    description: str
    involves_personal_data: bool
    data_classification: Literal["public","internal","confidential","restricted"]
    ai_system_approved: bool
    professional_output_without_review: bool
    creates_deceptive_content: bool
    discriminatory_purpose: bool
    external_facing: bool

    def classify(self) -> tuple[UseCategory, str]:
        if self.discriminatory_purpose:
            return "prohibited", "AI use for discriminatory purpose is prohibited"
        if self.creates_deceptive_content:
            return "prohibited", "AI-generated deceptive content is prohibited"
        if not self.ai_system_approved:
            return "prohibited", "AI system not approved for work use"
        if self.professional_output_without_review:
            return "prohibited", "Professional output requires human expert review"
        if self.data_classification == "restricted":
            return "prohibited", "Restricted data must not be processed by AI systems"
        if self.data_classification == "confidential" and not self.ai_system_approved:
            return "prohibited", "Confidential data requires approved AI system"
        if self.involves_personal_data and self.external_facing:
            return "restricted", "External-facing personal data AI use requires DPO review"
        if self.data_classification in ("confidential","internal"):
            return "restricted", "Approved AI system required; do not share with consumer tools"
        return "permitted", "Use is within general guidelines"

def screen_use_cases(cases: list[AiUseCase]) -> dict:
    results = [c.classify() for c in cases]
    cats = [r[0] for r in results]
    return {
        "total": len(cases),
        "permitted": cats.count("permitted"),
        "restricted": cats.count("restricted"),
        "prohibited": cats.count("prohibited"),
        "prohibited_cases": [
            {"description": c.description, "reason": r[1]}
            for c, r in zip(cases, results) if r[0] == "prohibited"
        ],
    }
